class Solution {
public:
    vector<vector<int>> largeGroupPositions(string s) {
        vector<vector<int>> res;
        int start = 0, end = 0;
        for (int i = 0; i < s.size(); i++) {
            if (i == s.size() - 1 || s[i] != s[i + 1]) {
                if (i - start + 1 >= 3) {
                    res.push_back({start, i});
                }
                start = i + 1;
                end = i;
            } else {
                end = i;
            }
        }
        return res;
    }
};
